// Clean up initial summary for downstream use
// This content feeds directly into prompt_perso_prof AND gets inserted to SB later
const summaryRaw = $('Initial_summary1').first().json.text || '';
const reportId = $('Process Survey Data1').first().json.report_id;

// Clean markdown formatting, convert to HTML (same logic as original)
let content = summaryRaw
  .replace(/###\s*\*\*([^*]+)\*\*/g, '<h5>$1</h5>')
  .replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>')
  .replace(/\*([^*]+)\*/g, '$1')
  .trim();

return [{
  json: {
    report_id: reportId,
    content: content
  }
}];

// ---------------- CONFIG ----------------
const SUBHEADER_PATTERNS_ALL = {
  en: {
  approach: [
    "Personality and Interaction Style",
    "Impact in Different Environments",
    "Key Insight"
  ],
  strengths: [
    "Identifying Your Core Strengths",
    "Leveraging Strengths in Your Career",
    "Key Insight"
  ],
  development: [
    "Understanding Potential Growth Areas",
    "Implications for Your Growth",
    "Key Insight"
  ],
  values: [
    "Identifying Your Core Values",
    "Values in Career Decisions",
    "Key Insight"
  ]
},
  nl: {
  approach: [
    "Persoonlijkheid en interactiestijl",
    "Impact in verschillende omgevingen",
    "Belangrijkste inzicht"
  ],
  strengths: [
    "Je kernkwaliteiten in kaart",
    "Je sterke punten benutten in je loopbaan",
    "Belangrijkste inzicht"
  ],
  development: [
    "Inzicht in je groeigebieden",
    "Wat dit betekent voor je groei",
    "Belangrijkste inzicht"
  ],
  values: [
    "Je kernwaarden in kaart",
    "Waarden in loopbaankeuzes",
    "Belangrijkste inzicht"
  ]
}
};
const __lang = ($('Process Survey Data1').first().json.preferred_language === 'nl') ? 'nl' : 'en';
const SUBHEADER_PATTERNS = SUBHEADER_PATTERNS_ALL[__lang];

// ---------------- HELPERS ----------------
function cleanMarkdown(text) {
  return text
    .replace(/\*\*(.*?)\*\*/g, '$1')
    .replace(/__(.*?)__/g, '$1')
    .replace(/\*(.*?)\*/g, '$1')
    .trim();
}

function extractSections(content, sectionType) {
  const patterns = SUBHEADER_PATTERNS[sectionType] || [];
  if (patterns.length === 0) return [];

  const regex = new RegExp(`(${patterns.join('|')}):?`, 'gi');
  const parts = content.split(regex).filter(Boolean);
  const sections = [];

  for (let i = 0; i < parts.length; i++) {
    const p = parts[i].trim();
    if (patterns.some(ph => new RegExp(ph, 'i').test(p))) {
      const subheader = p.replace(/:$/, '').trim();
      const next = parts[i + 1] ? parts[i + 1].trim() : '';
      sections.push({ subheader, content: next });
      i++;
    }
  }
  // Fallback: if no known subheaders matched (e.g. localized text the
  // patterns don't cover), keep the whole section as one block instead of
  // dropping it. Guarantees no section is ever lost to a pattern miss.
  if (sections.length === 0) {
    const whole = content.trim();
    return whole ? [{ subheader: '', content: whole }] : [];
  }
  return sections;
}

// ---------------- SOURCE DATA ----------------
const narrativeData = $('generate_personality_narrative1').first().json;
const reportId = $('Process Survey Data1').first().json.report_id;

// Get the init_summary content from Prep node (already cleaned HTML)
const initSummaryContent = $('Prep init_summary').first().json.content;

// ============== Extract personality_scores tag ==============
// The prompt appends a hidden <personality_scores>{...}</personality_scores>
// tag at the very end of the narrative. Pull it out, parse the JSON, and
// strip the tag from the text BEFORE we parse sections so the prose stays
// clean. The scores get attached to the `approach` section row's metadata
// column, where the dashboard's Personality Radar reads them from.
let personalityScores = null;
let narrativeText = narrativeData.text || '';
const scoresMatch = narrativeText.match(/<personality_scores>\s*([\s\S]*?)\s*<\/personality_scores>/i);
if (scoresMatch) {
  try {
    personalityScores = JSON.parse(scoresMatch[1].trim());
  } catch (err) {
    console.warn('[extract_report_sections] personality_scores JSON parse failed:', err.message);
  }
  narrativeText = narrativeText.replace(scoresMatch[0], '').trim();
}
// ============================================================

// ---------------- NARRATIVE EXTRACTION ----------------
const titleRegex = /#{1,3}\s*([^\n#]+)/g;
const titles = [];
let match;
while ((match = titleRegex.exec(narrativeText)) !== null) {
  titles.push(match[1].trim());
}

const contents = narrativeText.split(/#{1,3}\s*[^\n#]+\n*/g);
contents.shift();

const sectionTypes = ['approach', 'strengths', 'development', 'values'];
const parsedSections = [];

for (let i = 0; i < contents.length; i++) {
  const sectionType = sectionTypes[i];
  const raw = cleanMarkdown(contents[i]);
  parsedSections.push(extractSections(raw, sectionType));
}

// ---------------- OUTPUT ALL 5 SECTIONS ----------------
// init_summary + 4 narrative sections, all inserted to SB in one batch.
// Approach gets the personality_scores attached as metadata.
// Other sections leave metadata null.
const allSections = [
  {
    section_type: 'init_summary',
    title: 'Initial Summary',
    content: initSummaryContent,
    isRawContent: true,
    metadata: null
  },
  {
    section_type: 'approach',
    title: titles[0] || null,
    content: parsedSections[0] || [],
    metadata: personalityScores ? { personality_scores: personalityScores } : null
  },
  { section_type: 'strengths',   title: titles[1] || null, content: parsedSections[1] || [], metadata: null },
  { section_type: 'development', title: titles[2] || null, content: parsedSections[2] || [], metadata: null },
  { section_type: 'values',      title: titles[3] || null, content: parsedSections[3] || [], metadata: null }
];

return allSections
  .filter(s => s.content && (s.isRawContent || (Array.isArray(s.content) && s.content.length > 0)))
  .map(s => {
    let formatted;

    if (s.isRawContent) {
      formatted = s.content;
    } else {
      formatted = s.content.map(block => {
        const subheader = block.subheader && block.subheader.trim()
          ? `<h5>${block.subheader}</h5>\n\n`
          : '';
        const text = block.content || '';
        return `${subheader}${text}`;
      }).join('\n\n');
    }

    // CRITICAL: every row MUST have the same set of keys. PostgREST
    // bulk insert (PGRST102) rejects arrays where keys differ across rows.
    // metadata is always present and is null unless this is the approach row.
    return {
      report_id: reportId,
      section_type: s.section_type,
      title: s.title,
      content: formatted,
      metadata: s.metadata ?? null,
      language: __lang
    };
  });

